import { Portal as PortalPrimitive } from '@radix-ui/react-portal';
import { cva } from 'class-variance-authority';
import {
  Toaster as SonnerToaster,
  type ToasterProps as SonnerToasterProps,
} from 'sonner';

import CancelIcon from '../icons/CancelIcon';
import CheckIcon from '../icons/CheckIcon';
import CloseIcon from '../icons/CloseIcon';
import { cn } from '../utils/cn';

const toastVariants = cva('group', {
  variants: {
    variant: {
      success: 'border-success-700 bg-success-100 text-success-900',
      error: 'border-danger-700 bg-danger-100 text-danger-900',
    },
  },
});

export type ToasterProps = Omit<SonnerToasterProps, 'id'> & {
  /**
   * `id` is required by our Toaster to disambiguate between multiple toasters in
   * the same page.
   */
  id: string;
};

/**
 * A container component for showing toast notifications, built on top of the `sonner` library.
 *
 * This module provides both a component (`Toaster`) and a function (`toastFor`)
 * to show notifications in Toasters.
 *
 * ## How to toast
 *
 * To toast, establish a `Toaster` and then use `toastFor` to show notifications.
 *
 * In a Root-level or feature-level component:
 * ```tsx
 * <Toaster id={PLANTS_TOASTER_ID} />
 * ```
 *
 * Then in any component rendered in the same feature tree (page):
 *
 * ```tsx
 * <Button onClick={() => toastFor(PLANTS_TOASTER_ID).success('Changes saved successfully')}>
 *   Show Success Toast
 * </Button>
 *  <Button onClick={() => toastFor(PLANTS_TOASTER_ID).error('There was an error saving changes')}>
 *   Show Error Toast
 * </Button>
 * ```
 */
const Toaster = ({ ...props }: ToasterProps) => {
  return (
    <PortalPrimitive>
      <SonnerToaster
        position="top-center"
        closeButton
        icons={{
          success: (
            <span className="flex size-5 items-center justify-center rounded-full bg-success-700">
              <CheckIcon className="size-3 text-background" />
            </span>
          ),
          error: <CancelIcon className="size-5 text-danger-700" />,
          close: <CloseIcon className="size-5 text-muted-foreground" />,
        }}
        toastOptions={{
          unstyled: true,
          classNames: {
            toast: cn(
              'flex min-w-[300px] items-center gap-2 rounded border p-4 shadow-lg'
            ),
            title: cn('mr-2'),
            success: cn(toastVariants({ variant: 'success' })),
            error: cn(toastVariants({ variant: 'error' })),
            closeButton: cn(
              'static order-last ml-auto w-5 max-w-5 shrink-0 cursor-pointer',
              'bg-transparent p-0'
            ),
          },
        }}
        {...props}
      />
    </PortalPrimitive>
  );
};

export { Toaster };
